 Begin CmpMap 	# Compound Mapping
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    MapA = 	# First component Mapping
       Begin TranMap 	# Compound Transformation Mapping
          Nin = 1 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          MapA = 	# Mapping for forward transformation
             Begin MathMap 	# Transformation using mathematical functions
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                Fwd1 = "y=x+1.5" 	# Forward function 1
                Inv1 = "x=y-1.5" 	# Inverse function 1
             End MathMap
          MapB = 	# Mapping for inverse transformation
             Begin MathMap 	# Transformation using mathematical functions
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                Fwd1 = "y=x*2.5" 	# Forward function 1
                Inv1 = "x=y/2.5" 	# Inverse function 1
             End MathMap
       End TranMap
    MapB = 	# Second component Mapping
       Begin TranMap 	# Compound Transformation Mapping
          Nin = 1 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          MapA = 	# Mapping for forward transformation
             Begin MathMap 	# Transformation using mathematical functions
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                Fwd1 = "y=x+3.5" 	# Forward function 1
                Inv1 = "x=y-3.5" 	# Inverse function 1
             End MathMap
          MapB = 	# Mapping for inverse transformation
             Begin MathMap 	# Transformation using mathematical functions
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                Fwd1 = "y=x*7.5" 	# Forward function 1
                Inv1 = "x=y/7.5" 	# Inverse function 1
             End MathMap
       End TranMap
 End CmpMap
